+fn find_substring_column(haystack: &str, needle: &str) -> Option<usize> {
+    haystack.find(needle).map(|idx| idx + 1)
+}
+
+fn find_regex_column(haystack: &str, regex: &Regex) -> Option<usize> {
+    regex.find(haystack).map(|m| m.start() + 1)
+}
