+            out.push((m.as_str().to_string(), m.start() + 1));
+        }
+    }
+
+    for caps in import_dynamic_regex().captures_iter(line) {
+        if let Some(m) = caps.get(1) {
+            out.push((m.as_str().to_string(), m.start() + 1));
+        }
+    }
+
+    out
+}
